1	import { quote, claim, type Customer, type Item, type Incident } from "./claim-office.js";
2	
3	export interface CliResult {
4	  stdout: string;
5	  stderr: string;
6	  exitCode: number;
7	}
8	
9	interface QuoteStep {
10	  op?: "quote";
11	  items: Item[];
12	}
13	
14	interface ClaimStep {
15	  op: "claim";
16	  policy: number;
17	  incident: Incident;
18	}
19	
20	type Step = QuoteStep | ClaimStep;
21	
22	interface Scenario {
23	  customer: Customer;
24	  steps: Step[];
25	}
26	
27	const KNOWN_ITEM_TYPES = new Set(["sword", "amulet", "staff", "potion", "rune", "moonstone"]);
28	
29	export function runScenario(scenarioJson: string): CliResult {
30	  const scenario: Scenario = JSON.parse(scenarioJson);
31	  const results = [];
32	  for (const step of scenario.steps) {
33	    if (step.op === "claim") {
34	      const policyStep = scenario.steps[step.policy] as QuoteStep;
35	      const policyTypes = new Set(policyStep.items.map((item) => item.type));
36	      for (const damage of step.incident.damages) {
37	        if (!policyTypes.has(damage.itemType)) {
38	          return { stdout: "", stderr: `claim damage itemType ${damage.itemType} not in policy`, exitCode: 1 };
39	        }
40	      }
41	      results.push(claim({ items: policyStep.items }, step.incident));
42	      continue;
43	    }
44	    for (const item of step.items) {
45	      if (!KNOWN_ITEM_TYPES.has(item.type)) {
46	        return { stdout: "", stderr: `unknown item type: ${item.type}`, exitCode: 1 };
47	      }
48	    }
49	    results.push({ premium: quote(scenario.customer, step.items) });
50	  }
51	  return { stdout: JSON.stringify({ results }), stderr: "", exitCode: 0 };
52	}
